import ShowBlogs from './components/ShowBlogs'
import AddBlog from './components/AddBlog'
import SingleBlog from './components/SingleBlog'
import EditBlog from './components/EditBlog'
export default [
  {path:'/',component:ShowBlogs,meta:{title:'博客首页'}},
  {path:'/add',component:AddBlog,meta:{title:'添加博客'}},
  {path:'/blog/:id',component:SingleBlog,meta:{title:'博客详情'}},
  {path:'/edit/:id',component:EditBlog,meta:{title:'编辑博客'}}
]



