<template>
  <div id="add-blog">
    <h1>添加博客</h1>
    <form v-if="!submmited">
      <label>博客标题</label>
      <input type="search" v-model="blog.title" required>
      <label>博客内容</label>
      <textarea v-model="blog.content"></textarea>
      <div id="checkbox">
        <label>Vue.js</label>
        <input type="checkbox" value="Vue.js" v-model="blog.categories">
        <label>Node.js</label>
        <input type="checkbox" value="Node.js" v-model="blog.categories">
        <label>React.js</label>
        <input type="checkbox" value="React.js" v-model="blog.categories">
        <label>Angular.js</label>
        <input type="checkbox" value="Angular.js" v-model="blog.categories">
      </div>
      <label>作者</label>
      <input type="search" v-model="blog.author" required>

      <button v-on:click.prevent="post">添加博客</button>
    </form>
    <div v-if="submmited">
      <h3>恭喜您,您的博客发布成功！</h3>
    </div>
    <div id="preview">
      <h3>博客总览</h3>
      <p>博客标题：{{blog.title}}</p>
      <p>博客内容：{{blog.content}}</p>
      <!--<p></p>-->
      <p>博客分类：</p>
      <ul>
        <li v-for="categories in blog.categories" :key="categories">{{categories}}</li>
      </ul>
      <p>作者：{{blog.author}}</p>
    </div>
  </div>
</template>

<script>
  import axios from 'axios'

  export default {
    name: 'add-blog',
    data() {
      return {
        blog: {
          title: "",
          content: "",
          categories: [],
          author: ""
        },
        submmited: false
      };
    },
    computed: {},
    methods: {
      // http://jsonplaceholder.typicode.com/
      post: function () {
        // this.$http.post("https://vuedemo-dcdfe.firebaseio.com/posts.json", this.blog)
        if (this.blog.title.length === 0 || this.blog.title.trim().length === 0) {
          alert("标题不能为空！")
        } else if (this.blog.content.trim().length < 20) {
          alert("内容过少，有效内容（不包括空格）不能少于20个字符！")
        } else if (this.blog.categories.length === 0) {
          alert("请至少选择一种类别")
        } else if (this.blog.author.length === 0) {
          alert("作者名字不能为空！")
        } else {
          axios.post("/posts.json", this.blog)
            .then((data) => {
              // console.log(data);
              this.submmited = true
            })
        }
      }
    }
  };
</script>

<style scoped>
  #add-blog * {
    box-sizing: border-box;
  }

  #add-blog {
    margin: 20px auto;
    max-width: 600px;
    padding: 20px;
  }

  label {
    display: block;
    margin: 20px 0 10px;
  }

  input[type="search"], textarea, select {
    display: block;
    width: 100%;
    padding: 8px;
    border-radius: 5px;
  }

  textarea {
    height: 200px;
  }

  #checkbox label {
    display: inline-block;
    margin-top: 0;
  }

  #checkbox input {
    display: inline-block;
    margin-right: 10px;
  }

  button {
    display: block;
    margin: 20px 0;
    background-color: crimson;
    color: white;
    border: 0;
    padding: 14px;
    border-radius: 4px;
    font-size: 18px;
    cursor: pointer;
  }

  #preview {
    padding: 10px 20px;
    border: 1px dotted #ccc;
    margin: 30px 0;
  }

  h3 {
    margin-top: 10px;
  }
</style>



